mapper.select:
SELECT g.goods_id AS goodsId, g.goods_code AS goodsCode, g.goods_name AS goodsName, g.goods_model AS goodsModel, g.goods_unit AS goodsUnit, SUM(pg.goods_num) AS totalNum, SUM(pg.total) AS totalAmount FROM t_purchase_list_goods pg INNER JOIN t_purchase_list pl ON pg.purchase_list_id = pl.purchase_list_id INNER JOIN t_goods g ON pg.goods_id = g.goods_id
AND pl.purchase_date >= #{startDate} AND pl.purchase_date <= #{endDate} AND g.goods_type_id = #{typeId}
GROUP BY g.goods_id ORDER BY totalAmount DESC

SELECT g.goods_id AS goodsId, g.goods_code AS goodsCode, g.goods_name AS goodsName, g.goods_model AS goodsModel, g.goods_unit AS goodsUnit, SUM(sg.goods_num) AS totalNum, SUM(sg.total) AS totalAmount FROM t_sale_list_goods sg INNER JOIN t_sale_list sl ON sg.sale_list_id = sl.sale_list_id INNER JOIN t_goods g ON sg.goods_id = g.goods_id
AND sl.sale_date >= #{startDate} AND sl.sale_date <= #{endDate} AND g.goods_type_id = #{typeId}
GROUP BY g.goods_id ORDER BY totalAmount DESC

SELECT s.supplier_id AS supplierId, s.supplier_name AS supplierName, COUNT(pl.purchase_list_id) AS orderCount, SUM(pl.amount_payable) AS totalAmount FROM t_purchase_list pl INNER JOIN t_supplier s ON pl.supplier_id = s.supplier_id
AND pl.purchase_date >= #{startDate} AND pl.purchase_date <= #{endDate}
GROUP BY s.supplier_id ORDER BY totalAmount DESC

SELECT c.customer_id AS customerId, c.customer_name AS customerName, COUNT(sl.sale_list_id) AS orderCount, SUM(sl.amount_payable) AS totalAmount FROM t_sale_list sl INNER JOIN t_customer c ON sl.customer_id = c.customer_id
AND sl.sale_date >= #{startDate} AND sl.sale_date <= #{endDate}
GROUP BY c.customer_id ORDER BY totalAmount DESC

SELECT sale_date AS saleDate, SUM(amount_payable) AS totalAmount
FROM t_sale_list

    AND sale_date >= #{startDate}
    AND sale_date <= #{endDate}

GROUP BY sale_date
ORDER BY sale_date

SELECT DATE_FORMAT(sale_date, '%Y-%m') AS saleMonth, SUM(amount_payable) AS totalAmount
FROM t_sale_list

    AND sale_date >= #{startDate}
    AND sale_date <= #{endDate}

GROUP BY saleMonth
ORDER BY saleMonth
